1	//! R1 — theory-view CENTER section fragments.
2	//!
3	//! The `main/message`, `main/rules`, `main/tactic` panes share one skeleton
4	//! (BEHAVIOR.md §4–7): a plain-text document of headed blocks —
5	//! `<h2>HEADING</h2>` on its own line, then a `<p class="monospace rules">`
6	//! paragraph glued to the first body line and closed on the last — put through
7	//! the per-line postprocess and wrapped in the `{html,title}` envelope. Blocks
8	//! follow each other with no blank line between; empty bodies render per the
9	//! block's [`EmptyRender`] mode.
10	//!
11	//! `main/help` (BEHAVIOR.md §8) is a different, single-line template rendered
12	//! by [`render_help_pane`]: the env line + the fixed static help block, with
13	//! NO per-line postprocess.
14	
15	use crate::html::{escape_text, html_envelope, postprocess_lines};
16	use crate::model::{ContentPane, EmptyRender, HelpPane};
17	
18	/// The fixed help block shown under the env line of every `main/help`
19	/// response, byte-identical across all 81 corpus captures [S09]. Verbatim
20	/// captured output (compatibility content), including the stray `</span>`
21	/// after the Tamarin span.
22	pub const HELP_STATIC_HTML: &str = include_str!("help_static.html");
23	
24	/// Render a center-section content pane to its response-body bytes (the
25	/// `{html,title}` envelope). The entry point for `main/message`, `main/rules`
26	/// and `main/tactic`.
27	pub fn render_pane(pane: &ContentPane) -> String {
28	    let mut chunks: Vec<String> = Vec::new();
29	    for block in &pane.blocks {
30	        if block.body.is_empty() {
31	            match block.when_empty {
32	                EmptyRender::Omit => continue,
33	                EmptyRender::BlankLine => {
34	                    chunks.push(String::new());
35	                    continue;
36	                }
37	                EmptyRender::Keep => {}
38	            }
39	        }
40	        let mut chunk = String::new();
41	        chunk.push_str("<h2>");
42	        chunk.push_str(&escape_text(&block.heading));
43	        chunk.push_str("</h2>\n<p class=\"monospace rules\">");
44	        chunk.push_str(&block.body.lines.join("\n"));
45	        chunk.push_str("</p>");
46	        chunks.push(chunk);
47	    }
48	    html_envelope(&pane.title, &postprocess_lines(&chunks.join("\n")))
49	}
50	
51	/// Render the `main/help` pane to its response-body bytes.
52	///
53	/// Shape (BEHAVIOR.md §8): `<p>Theory: NAME (Loaded at TIME from ORIGIN)
54	/// BANNER</p>` + the static help block; title `Theory: NAME`. Single line —
55	/// no postprocess, no trailing newline. An empty banner leaves the observed
56	/// `) </p>` bytes; a non-empty banner is raw HTML passthrough.
57	pub fn render_help_pane(help: &HelpPane) -> String {
58	    let mut html = String::with_capacity(HELP_STATIC_HTML.len() + 256);
59	    html.push_str("<p>Theory: ");
60	    html.push_str(&escape_text(&help.theory_name));
61	    html.push_str(" (Loaded at ");
62	    html.push_str(&escape_text(&help.load_time));
63	    html.push_str(" from ");
64	    html.push_str(&escape_text(&help.origin));
65	    html.push_str(") ");
66	    html.push_str(&help.wf_banner_html);
67	    html.push_str("</p>");
68	    html.push_str(HELP_STATIC_HTML);
69	    let mut title = String::with_capacity(8 + help.theory_name.len());
70	    title.push_str("Theory: ");
71	    title.push_str(&help.theory_name);
72	    html_envelope(&title, &html)
73	}
