1	//! R5 — the theory-path grammar (URL <-> structured path).
2	//!
3	//! The wildcard tail after `/thy/trace/<idx>/main/` (and the same grammar the
4	//! `del/path/…` + `verify/…` routes take) maps to a structured [`ThyPath`].
5	//! Everything below is pinned by the round-2 probes (QUERIES.log [S14][L08]–
6	//! [L13]) — the corpus href inventory on the render side and the live
7	//! acceptance battery on the parse side.
8	//!
9	//! ## Segment model
10	//! The raw tail splits on `/` FIRST; each segment is then percent-decoded
11	//! independently (`me%73sage` matches `message`; an encoded `%2F` does NOT
12	//! split — `proof/foo%2F_` names the lemma `foo/_` [L09]). Decoding: a valid
13	//! `%XX` pair becomes that byte and the byte sequence is read as UTF-8 with
14	//! U+FFFD replacement for invalid sequences [L12]; an INVALID percent sequence
15	//! stays literal (`a%zzb`, trailing `a%`, `a%2` [L12]); `+` is NOT a space
16	//! [L12]. Head keywords match exactly and case-sensitively (`MESSAGE`,
17	//! `cases/RAW` rejected [L08][L09]).
18	//!
19	//! ## Acceptance shape
20	//! Extra segments AFTER a complete match are ignored (`help/extra`,
21	//! `message/`, `cases/raw/0/0/extra`, `lemma/foo/extra` all accepted
22	//! [L09][L11]); a missing required argument rejects (`proof`, `cases/raw/1`
23	//! [L08][L11]); name arguments accept ANY decoded text including the empty
24	//! string (`edit/`, `proof//_` accepted [L11]) — existence of the named lemma
25	//! is a resolution question, not a parse question [L08].
26	//!
27	//! ## The numeric-segment grammar ([L10])
28	//! The two `cases` indices parse like a Haskell `reads @Int` prefix: optional
29	//! whitespace, balanced parens, an optional `-` (whitespace allowed after it),
30	//! then one integer lexeme — decimal, or `0x`/`0X` hex, `0o`/`0O` octal,
31	//! `0b`/`0B` binary. Junk after the lexeme is IGNORED at top level (`1abc`,
32	//! `1_`, `(1)x` accepted) but not inside parens (`(1x)` rejected); a decimal
33	//! lexeme that continues as a FLOAT (`.` + digit, or `e`/`E` + optional sign +
34	//! digit) rejects (`1.0`, `1e2`); a leading underscore rejects (`_1` lexes as
35	//! an identifier, not a number — the underscore-prefix quirk) while interior/
36	//! trailing underscores are junk-tolerated (`1_0`, `1_`, `0x_1`); `+1` and
37	//! `--1` reject. The VALUE never changes the response bytes (0/0 vs 9/9 vs
38	//! -1/0 bodies byte-identical [L10]), so out-of-usize values are clamped
39	//! (negative → 0, overflow → `usize::MAX`) as a documented arbitrary choice.
40	//!
41	//! ## Render side ([S14][L13])
42	//! Rendered segments across the whole corpus + live pages contain only
43	//! `[A-Za-z0-9_.]` verbatim plus the single escape `%3C`/`%3E` in
44	//! `add/%3Cfirst%3E` (`<first>`). Encoding of other bytes is UNOBSERVABLE (the
45	//! metachar-filename channel collapsed: download/get_and_append URLs derive
46	//! from the theory NAME [L13]); the documented choice is: keep RFC3986
47	//! unreserved bytes (`A-Z a-z 0-9 - . _ ~`) raw, percent-encode every other
48	//! UTF-8 byte as uppercase `%XX` — which reproduces every observed href byte.
49	//! Numeric arguments render as plain decimal (`cases/raw/0/0`); the version
50	//! index in full hrefs is plain decimal too and is out of this grammar (it
51	//! precedes the handler).
52	//!
53	//! Out of the producer link vocabulary (no [`ThyPath`] constructor, parse →
54	//! `None`): `method/{lemma}/{n}[/path…]` — the server accepts it ([L11]) but
55	//! no fragment link the producers emit uses it, and the interface contract
56	//! omits it. `sources` is NOT a head (rejected live [L11]); the sources panes
57	//! live under `cases/{raw|refined}/{i}/{j}`.
58	
59	use crate::model::ThyPath;
60	
61	/// Percent-decode one raw URL segment (observed rules [L12]): valid `%XX`
62	/// pairs become bytes, invalid percent sequences stay literal, the byte string
63	/// is read as UTF-8 with U+FFFD replacement, `+` is left alone.
64	fn decode_segment(raw: &str) -> String {
65	    let bytes = raw.as_bytes();
66	    let mut out: Vec<u8> = Vec::with_capacity(bytes.len());
67	    let mut i = 0;
68	    while i < bytes.len() {
69	        if bytes[i] == b'%'
70	            && i + 3 <= bytes.len()
71	            && bytes[i + 1].is_ascii_hexdigit()
72	            && bytes[i + 2].is_ascii_hexdigit()
73	        {
74	            let hi = (bytes[i + 1] as char).to_digit(16).unwrap() as u8;
75	            let lo = (bytes[i + 2] as char).to_digit(16).unwrap() as u8;
76	            out.push(hi << 4 | lo);
77	            i += 3;
78	        } else {
79	            out.push(bytes[i]);
80	            i += 1;
81	        }
82	    }
83	    String::from_utf8_lossy(&out).into_owned()
84	}
85	
86	/// Percent-encode one segment for an href: RFC3986 unreserved bytes raw,
87	/// everything else as uppercase `%XX` per UTF-8 byte. Reproduces every
88	/// observed rendered segment ([S14]); beyond `[A-Za-z0-9_.]` and `<`/`>` the
89	/// exact server-side set is UNOBSERVABLE ([L13]) — this is the documented
90	/// choice.
91	fn encode_segment(s: &str) -> String {
92	    let mut out = String::with_capacity(s.len());
93	    for &b in s.as_bytes() {
94	        match b {
95	            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'.' | b'_' | b'~' => {
96	                out.push(b as char)
97	            }
98	            _ => out.push_str(&format!("%{b:02X}")),
99	        }
100	    }
101	    out
102	}
103	
104	/// Parse a numeric segment the way the live server accepts one ([L10]): a
105	/// Haskell-`reads`-shaped integer prefix. Returns the clamped value.
106	fn parse_numeric(seg: &str) -> Option<usize> {
107	    let chars: Vec<char> = seg.chars().collect();
108	    // Top level: anything after the parsed item is ignored junk.
109	    let (value, _end) = parse_int_item(&chars, 0)?;
110	    Some(if value < 0 {
111	        0
112	    } else {
113	        usize::try_from(value).unwrap_or(usize::MAX)
114	    })
115	}
116	
117	/// One parenthesized/signed integer item starting at `pos` (whitespace
118	/// skipped). The item's END is returned: the top-level caller ignores what
119	/// follows it, while a paren frame requires its `)` to follow directly
120	/// ([L10]: `(1)x` accepted, `(1x)` rejected).
121	fn parse_int_item(chars: &[char], pos: usize) -> Option<(i128, usize)> {
122	    let mut i = skip_ws(chars, pos);
123	    if i < chars.len() && chars[i] == '(' {
124	        let (v, after) = parse_int_item(chars, i + 1)?;
125	        let j = skip_ws(chars, after);
126	        if j < chars.len() && chars[j] == ')' {
127	            return Some((v, j + 1));
128	        }
129	        return None;
130	    }
131	    let negative = if i < chars.len() && chars[i] == '-' {
132	        i = skip_ws(chars, i + 1);
133	        true
134	    } else {
135	        false
136	    };
137	    let (magnitude, after) = parse_int_lexeme(chars, i)?;
138	    Some((if negative { -magnitude } else { magnitude }, after))
139	}
140	
141	fn skip_ws(chars: &[char], mut i: usize) -> usize {
142	    while i < chars.len() && chars[i].is_whitespace() {
143	        i += 1;
144	    }
145	    i
146	}
147	
148	/// One integer lexeme: decimal, or `0x`/`0o`/`0b` (either case) with at least
149	/// one digit of the base. A decimal lexeme that continues as a float (`.`
150	/// digit / `e`/`E` [sign] digit) is NOT an integer ([L10]: `1.0`, `1e2`
151	/// rejected while `1abc`, `1.x`, `1ex` are junk-tolerated).
152	fn parse_int_lexeme(chars: &[char], i: usize) -> Option<(i128, usize)> {
153	    if i >= chars.len() || !chars[i].is_ascii_digit() {
154	        return None;
155	    }
156	    // Radix-prefixed form.
157	    if chars[i] == '0' && i + 1 < chars.len() {
158	        let radix = match chars[i + 1] {
159	            'x' | 'X' => Some(16),
160	            'o' | 'O' => Some(8),
161	            'b' | 'B' => Some(2),
162	            _ => None,
163	        };
164	        if let Some(radix) = radix {
165	            let mut j = i + 2;
166	            let mut v: i128 = 0;
167	            while j < chars.len() && chars[j].is_digit(radix) {
168	                v = v.saturating_mul(radix as i128).saturating_add(chars[j].to_digit(radix).unwrap() as i128);
169	                j += 1;
170	            }
171	            if j > i + 2 {
172	                return Some((v, j));
173	            }
174	            // No digit after the prefix: fall through — the leading `0` is the
175	            // lexeme and `x…` is junk ([L10]: `0x_1` accepted).
176	        }
177	    }
178	    let mut j = i;
179	    let mut v: i128 = 0;
180	    while j < chars.len() && chars[j].is_ascii_digit() {
181	        v = v.saturating_mul(10).saturating_add((chars[j] as u8 - b'0') as i128);
182	        j += 1;
183	    }
184	    // Float guard.
185	    if j < chars.len() {
186	        match chars[j] {
187	            '.' if j + 1 < chars.len() && chars[j + 1].is_ascii_digit() => return None,
188	            'e' | 'E' => {
189	                let mut k = j + 1;
190	                if k < chars.len() && (chars[k] == '+' || chars[k] == '-') {
191	                    k += 1;
192	                }
193	                if k < chars.len() && chars[k].is_ascii_digit() {
194	                    return None;
195	                }
196	            }
197	            _ => {}
198	        }
199	    }
200	    Some((v, j))
201	}
202	
203	/// Parse a raw wildcard tail (still percent-encoded, `/`-separated) into a
204	/// structured path. `None` mirrors the live server's 404 surface for the
205	/// producer link vocabulary.
206	pub fn parse(raw: &str) -> Option<ThyPath> {
207	    let segs: Vec<String> = raw.split('/').map(decode_segment).collect();
208	    let s: Vec<&str> = segs.iter().map(String::as_str).collect();
209	    match s.as_slice() {
210	        ["help", ..] => Some(ThyPath::Help),
211	        ["message", ..] => Some(ThyPath::Message),
212	        ["rules", ..] => Some(ThyPath::Rules),
213	        ["tactic", ..] => Some(ThyPath::Tactic),
214	        ["cases", kind @ ("raw" | "refined"), i, j, ..] => Some(ThyPath::Sources {
215	            refined: *kind == "refined",
216	            source_idx: parse_numeric(i)?,
217	            case_idx: parse_numeric(j)?,
218	        }),
219	        ["lemma", name, ..] => Some(ThyPath::Lemma((*name).to_string())),
220	        ["proof", lemma, sub @ ..] => Some(ThyPath::Proof {
221	            lemma: (*lemma).to_string(),
222	            sub: sub.iter().map(|s| s.to_string()).collect(),
223	        }),
224	        ["edit", name, ..] => Some(ThyPath::Edit((*name).to_string())),
225	        ["add", pos, ..] => Some(ThyPath::Add((*pos).to_string())),
226	        ["delete", name, ..] => Some(ThyPath::Delete((*name).to_string())),
227	        _ => None,
228	    }
229	}
230	
231	/// Render a structured path to its href segments (percent-encoded; join with
232	/// `/` for the wildcard tail). Byte-reproduces every harvested corpus href
233	/// tail in the vocabulary ([S14], tests/r5_path_grammar.rs).
234	pub fn render(path: &ThyPath) -> Vec<String> {
235	    match path {
236	        ThyPath::Help => vec!["help".into()],
237	        ThyPath::Message => vec!["message".into()],
238	        ThyPath::Rules => vec!["rules".into()],
239	        ThyPath::Tactic => vec!["tactic".into()],
240	        ThyPath::Sources {
241	            refined,
242	            source_idx,
243	            case_idx,
244	        } => vec![
245	            "cases".into(),
246	            if *refined { "refined" } else { "raw" }.into(),
247	            source_idx.to_string(),
248	            case_idx.to_string(),
249	        ],
250	        ThyPath::Lemma(name) => vec!["lemma".into(), encode_segment(name)],
251	        ThyPath::Proof { lemma, sub } => {
252	            let mut v = vec!["proof".into(), encode_segment(lemma)];
253	            v.extend(sub.iter().map(|s| encode_segment(s)));
254	            v
255	        }
256	        ThyPath::Edit(name) => vec!["edit".into(), encode_segment(name)],
257	        ThyPath::Add(pos) => vec!["add".into(), encode_segment(pos)],
258	        ThyPath::Delete(name) => vec!["delete".into(), encode_segment(name)],
259	    }
260	}
