61	fn add_link(idx: u64, pos: &str) -> String {
62	    format!(
63	        r#"<a class="internal-link add" href="{}">add lemma</a>"#,
64	        href(idx, &ThyPath::Add(pos.to_string()))
65	    )
66	}
