72	/// Push one lemma's lines (declaration, edit/delete, proof display).
73	fn push_lemma(elems: &mut Vec<String>, idx: u64, lemma: &LemmaEntry) {
74	    let name_html = escape_text(&lemma.name);
75	    let decl = format!("{} {}{}:", keyword("lemma"), name_html, lemma.attributes);
76	    let edit_delete = format!(
77	        r#"<a class="internal-link edit" href="{}">edit lemma</a>  or  <a class="internal-link delete" href="{}">delete lemma</a>"#,
78	        href(idx, &ThyPath::Edit(lemma.name.clone())),
79	        href(idx, &ThyPath::Delete(lemma.name.clone()))
80	    );
81	    // Header wrapper: one status span around declaration + edit/delete line,
82	    // carrying the proof ROOT's status class; none for `sorry` or an
83	    // incomplete (status-less root) proof [S16][S19].
84	    let header_status = match &lemma.proof {
85	        ProofDisplay::Tree(root) => match &root.status {
86	            Highlight::None => None,
87	            Highlight::Good => Some("hl_good"),
88	            Highlight::Bad => Some("hl_bad"),
89	            Highlight::Medium => Some("hl_medium"),
90	            Highlight::Replayed => Some("hl_superfluous"),
91	        },
92	        ProofDisplay::Unproven => None,
93	    };
94	    match header_status {
95	        Some(status) => {
96	            elems.push(format!(r#"<span class="{status}">{decl}"#));
97	            elems.push(format!("{edit_delete}</span>"));
98	        }
99	        None => {
100	            elems.push(decl);
101	            elems.push(edit_delete);
102	        }
103	    }
104	    // The quantifier/formula block goes BETWEEN the declaration and the
105	    // edit/delete line.
106	    let at = elems.len() - 1;
107	    let mut block: Vec<String> = Vec::new();
108	    if let [only_line] = lemma.formula.lines.as_slice() {
109	        let candidate = format!("  {} {}", lemma.quantifier, only_line);
110	        if escaped_width(&candidate) <= INLINE_WIDTH_LIMIT {
111	            block.push(candidate);
112	        }
113	    }
114	    if block.is_empty() {
115	        block.push(format!("  {}", lemma.quantifier));
116	        for line in &lemma.formula.lines {
117	            block.push(format!("  {line}"));
118	        }
119	    }
120	    elems.splice(at..at, block);
121	    // Proof display.
122	    match &lemma.proof {
123	        ProofDisplay::Unproven => elems.push(format!(
124	            r#"{} <a class="internal-link proof-step sorry-step" href="{}">{}</a>"#,
125	            keyword("by"),
126	            href(idx, &ThyPath::Proof { lemma: lemma.name.clone(), sub: vec![] }),
127	            keyword("sorry")
128	        )),
129	        ProofDisplay::Tree(root) => {
130	            elems.extend(prooftree::render_tree_lines(idx, &lemma.name, root))
131	        }
132	    }
133	}
134	
135	/// Render the inner HTML of the west proof-script pane (the content of the
136	/// page's proof-script container, final trailing space included).
137	pub fn render_index(pane: &ProofScriptPane) -> String {
138	    let idx = pane.index;
139	    let mut elems: Vec<String> = Vec::new();
140	    elems.push(format!(
141	        r#"{} <a class="internal-link help" href="{}">{}</a> {}"#,
142	        keyword("theory"),
143	        href(idx, &ThyPath::Help),
144	        escape_text(&pane.theory_name),
145	        keyword("begin")
146	    ));
147	    for item in &pane.items {
148	        elems.push(String::new());
149	        elems.push(format!(
150	            r#"<a class="internal-link" href="{}"><strong>{}</strong> {}</a>"#,
151	            href(idx, &item.target),
152	            item.label,
153	            item.annotation
154	        ));
155	    }
156	    elems.push(String::new());
157	    elems.push(add_link(idx, "<first>"));
158	    if pane.lemmas.is_empty() {
159	        // A lemma-less pane leaves TWO blank lines before `end` (both
160	        // lemma-less corpus panes [S16]).
161	        elems.push(String::new());
162	    }
163	    for lemma in &pane.lemmas {
164	        elems.push(String::new());
165	        push_lemma(&mut elems, idx, lemma);
166	        elems.push(String::new());
167	        elems.push(add_link(idx, &lemma.name));
168	    }
169	    elems.push(String::new());
170	    elems.push(keyword("end"));
171	    let mut out = postprocess_lines(&elems.join("\n"));
172	    out.push(' ');
173	    out
174	}
