1	//! R3 — proof-tree + proof-method HTML.
2	//!
3	//! Lays a pre-computed proof tree out as the logical lines embedded in the
4	//! west proof-script pane (the pane applies the shared per-line postprocess).
5	//! The tree SHAPE, per-node METHOD TEXT (pre-rendered HTML, possibly
6	//! multi-line) and per-node status are opaque inputs; this module owns the
7	//! line grammar, indentation, links and status-class attachment, all pinned
8	//! from the 478-pane capture corpus + live probes (BEHAVIOR.md §16–§18,
9	//! QUERIES.log [S19]–[S21], [L16]–[L18]).
10	//!
11	//! The grammar, per node at indent `d` with URL path `P` (= `proof/{lemma}`
12	//! plus one segment per case on the root-to-node walk, `_` for an unnamed
13	//! continuation):
14	//!
15	//!   * step line: `d` spaces + [`by ` prefix] + the step itself.
16	//!     - the `by ` prefix (keyword span + trailing space, wrapped in the
17	//!       node's status span) appears iff the node has NO cases and is not a
18	//!       terminal MARKER (`SOLVED`-style lines carry no `by`) [S19];
19	//!     - a Replayed-status node (a proof-script leftover) has NO proof-step
20	//!       link: the method is wrapped in the `hl_superfluous` status span
21	//!       [S20]; every other node's step is `<a class="internal-link
22	//!       proof-step CLS" href="/thy/trace/{idx}/main/P">METHOD</a>` where CLS
23	//!       is the status class (`sorry-step` for a status-less node);
24	//!     - a LIVE node's step ends with `<a class="internal-link remove-step"
25	//!       href="…same…"></a>`; the only non-live steps observed are the
26	//!       `sorry` slots (leaf, or carrying a replayed continuation) — replayed
27	//!       leftovers keep the remove affordance [S19][S20].
28	//!   * a single unnamed case continues at the SAME indent, path `P/_`,
29	//!     with no case/next/qed framing;
30	//!   * named cases: each case opens `case NAME` at `d+2` (wrapped in the
31	//!     CHILD's status span) followed by the child at `d+2`; siblings are
32	//!     separated by `next` at `d`, and the block closes with `qed` at `d` —
33	//!     `next`/`qed` carry the PARENT node's status span [S19][S21].
34	//!
35	//! Status→class: Good→`hl_good`, Bad→`hl_bad`, Medium→`hl_medium` (never
36	//! observed — assumed by pattern, see BEHAVIOR.md §18), Replayed→
37	//! `hl_superfluous`; None renders bare (no wrapping span) [S19][S20].
38	//!
39	//! Out of scope (solver-computed, other panes): the constraint-system pane,
40	//! the applicable-proof-methods listing, and the method text itself.
41	
42	use crate::html::escape_text;
43	use crate::model::{Highlight, ProofTree, ThyPath};
44	use crate::path;
45	
46	/// The status span class each highlight attaches, or None for bare rendering.
47	fn status_class(status: &Highlight) -> Option<&'static str> {
48	    match status {
49	        Highlight::None => None,
50	        Highlight::Good => Some("hl_good"),
51	        Highlight::Bad => Some("hl_bad"),
52	        Highlight::Medium => Some("hl_medium"),
53	        Highlight::Replayed => Some("hl_superfluous"),
54	    }
55	}
56	
57	/// Wrap `inner` in the node-status span (`<span class="CLS">…</span>`), or
58	/// return it unchanged for a status-less node.
59	fn wrap_status(status: &Highlight, inner: &str) -> String {
60	    match status_class(status) {
61	        Some(cls) => format!(r#"<span class="{cls}">{inner}</span>"#),
62	        None => inner.to_string(),
63	    }
64	}
65	
66	fn keyword(kw: &str) -> String {
67	    format!(r#"<span class="hl_keyword">{kw}</span>"#)
68	}
69	
70	/// Render a lemma's proof tree as the logical lines embedded in the west
71	/// pane (each element one document line; multi-line method texts keep their
72	/// embedded newlines). The pane joins these with the rest of the document
73	/// and applies the shared postprocess.
74	pub fn render_tree_lines(index: u64, lemma: &str, root: &ProofTree) -> Vec<String> {
75	    let mut lines = Vec::new();
76	    render_node(&mut lines, index, lemma, &mut Vec::new(), root, 0);
77	    lines
78	}
79	
80	/// Render a lemma's proof tree as one pre-postprocess document fragment
81	/// (the [`render_tree_lines`] elements joined with newlines).
82	pub fn render_tree(index: u64, lemma: &str, root: &ProofTree) -> String {
83	    render_tree_lines(index, lemma, root).join("\n")
84	}
85	
86	fn indent(n: usize) -> String {
87	    " ".repeat(n)
88	}
89	
90	/// One node: its step line, then its case layout (see module docs).
91	fn render_node(
92	    lines: &mut Vec<String>,
93	    index: u64,
94	    lemma: &str,
95	    sub: &mut Vec<String>,
96	    node: &ProofTree,
97	    depth: usize,
98	) {
99	    let ind = indent(depth);
100	    let href = format!(
101	        "/thy/trace/{index}/main/{}",
102	        path::render(&ThyPath::Proof {
103	            lemma: lemma.to_string(),
104	            sub: sub.clone(),
105	        })
106	        .join("/")
107	    );
108	    let mut step = ind.clone();
109	    // `by ` prefix: a case-less node that is a real method, not a terminal
110	    // marker ([S19]: contradiction / zero-case solve / sorry take `by`;
111	    // SOLVED does not).
112	    if node.cases.is_empty() && !node.terminal_marker {
113	        step.push_str(&wrap_status(&node.status, &format!("{} ", keyword("by"))));
114	    }
115	    if matches!(node.status, Highlight::Replayed) {
116	        // Replayed leftover: no proof-step link (nothing computed to show),
117	        // the method sits in the status span instead [S20].
118	        step.push_str(&wrap_status(&node.status, &node.method_text));
119	    } else {
120	        let cls = status_class(&node.status).unwrap_or("sorry-step");
121	        step.push_str(&format!(
122	            r#"<a class="internal-link proof-step {cls}" href="{href}">{}</a>"#,
123	            node.method_text
124	        ));
125	    }
126	    // Remove-step affordance: every step except the `sorry` slots — replayed
127	    // leftovers included (they remain addressable and removable) [S19][S20].
128	    if node.live {
129	        step.push_str(&format!(
130	            r#"<a class="internal-link remove-step" href="{href}"></a>"#
131	        ));
132	    }
133	    lines.push(step);
134	
135	    match node.cases.as_slice() {
136	        [] => {}
137	        [(name, child)] if name.is_empty() => {
138	            // Single unnamed continuation: same indent, path segment `_`.
139	            sub.push("_".to_string());
140	            render_node(lines, index, lemma, sub, child, depth);
141	            sub.pop();
142	        }
143	        cases => {
144	            let case_ind = indent(depth + 2);
145	            for (i, (name, child)) in cases.iter().enumerate() {
146	                if i > 0 {
147	                    lines.push(format!(
148	                        "{ind}{}",
149	                        wrap_status(&node.status, &keyword("next"))
150	                    ));
151	                }
152	                lines.push(format!(
153	                    "{case_ind}{}",
154	                    wrap_status(
155	                        &child.status,
156	                        &format!("{} {}", keyword("case"), escape_text(name))
157	                    )
158	                ));
159	                sub.push(name.clone());
160	                render_node(lines, index, lemma, sub, child, depth + 2);
161	                sub.pop();
162	            }
163	            lines.push(format!(
164	                "{ind}{}",
165	                wrap_status(&node.status, &keyword("qed"))
166	            ));
167	        }
168	    }
169	}
