1	//! R4 — the welcome / index page (`/`) and housekeeping bodies.
2	//!
3	//! The index page is a fixed frame (head + loading bar + "Running Tamarin
4	//! VERSION" header + logo + credits/license block + upload form) around three
5	//! slots: an optional one-shot flash paragraph right after `<body>`, the
6	//! version text, and the loaded-theory table rows. Everything else is
7	//! byte-constant — the frame segments are verbatim captured output
8	//! (compatibility content), including the doubled `</script></script>`
9	//! closers and the row cell's unclosed `<em>` (BEHAVIOR.md §19, QUERIES.log
10	//! [L19]–[L21]). No trailing newline.
11	//!
12	//! One row per loaded theory version, index ascending:
13	//!
14	//! ```text
15	//! <tr><td><a href="/thy/trace/IDX/overview/help">NAME</a></td>
16	//!     <td>TIME</td><td>Original | <em>Modified</td><td>ORIGIN</td></tr>
17	//! ```
18	//!
19	//! NAME/TIME/ORIGIN are opaque display strings, entity-escaped here (the
20	//! metachar-filename upload probe [L21] pins the escaping to the shared R1
21	//! set). ORIGIN is the load path for a disk theory and the bare uploaded
22	//! filename for an upload; a proof/upload-derived version shows the
23	//! `<em>Modified` cell, the initial load `Original`.
24	//!
25	//! Flash paragraph (`<p class="message">…</p>`, first child of `<body>`)
26	//! [L20]: upload success `Loaded new theory!`; a POST without a usable file
27	//! `Post request failed.`; a load error the pre-computed message text
28	//! (entity-escaped, embedded newlines preserved).
29	//!
30	//! Housekeeping bodies [L19]: `robots.txt` and the cancel acknowledgement
31	//! are fixed plain-text bodies without a trailing newline; a missing static
32	//! file answers a fixed plain-text body; the Invalid-Arguments page wraps
33	//! `<li>` message items in the observed error shell.
34	
35	use crate::html::escape_text;
36	use crate::model::{Banner, TheoryRow, Welcome};
37	
38	const PRE_FLASH: &str = include_str!("welcome_pre_flash.html");
39	const PRE_VERSION: &str = include_str!("welcome_pre_version.html");
40	const PRE_ROWS: &str = include_str!("welcome_pre_rows.html");
41	const POST_ROWS: &str = include_str!("welcome_post_rows.html");
42	
43	const INVALID_ARGS_PRE: &str = include_str!("invalid_args_pre.html");
44	const INVALID_ARGS_POST: &str = include_str!("invalid_args_post.html");
45	
46	/// `GET /robots.txt` body (no trailing newline) [L19].
47	pub const ROBOTS_BODY: &str = "User-agent: *";
48	
49	/// `GET /kill?path=…` acknowledgement body (no trailing newline) [L19].
50	pub const CANCEL_ACK_BODY: &str = "Canceled request!";
51	
52	/// Missing `/static/**` file body [L19].
53	pub const FILE_NOT_FOUND_BODY: &str = "File not found";
54	
55	/// The one-shot flash paragraph after `<body>`, or empty for a plain GET.
56	fn flash(banner: &Banner) -> String {
57	    let msg = match banner {
58	        Banner::None => return String::new(),
59	        Banner::Loaded => "Loaded new theory!".to_string(),
60	        Banner::Failed => "Post request failed.".to_string(),
61	        Banner::Custom(m) => escape_text(m),
62	    };
63	    format!("<p class=\"message\">{msg}</p>")
64	}
65	
66	fn row(r: &TheoryRow) -> String {
67	    format!(
68	        "<tr><td><a href=\"/thy/trace/{}/overview/help\">{}</a></td><td>{}</td><td>{}</td><td>{}</td></tr>",
69	        r.index,
70	        escape_text(&r.name),
71	        escape_text(&r.time),
72	        if r.modified { "<em>Modified" } else { "Original" },
73	        escape_text(&r.origin),
74	    )
75	}
76	
77	/// Render the index (`/`) page body.
78	pub fn render_welcome(w: &Welcome) -> String {
79	    let mut out = String::with_capacity(4096 + 256 * w.rows.len());
80	    out.push_str(PRE_FLASH);
81	    out.push_str(&flash(&w.banner));
82	    out.push_str(PRE_VERSION);
83	    out.push_str(&escape_text(&w.version));
84	    out.push_str(PRE_ROWS);
85	    for r in &w.rows {
86	        out.push_str(&row(r));
87	    }
88	    out.push_str(POST_ROWS);
89	    out
90	}
91	
92	/// Render the 400 Invalid-Arguments page around the given message items
93	/// (observed instance: `GET /kill` without a path) [L19].
94	pub fn render_invalid_args(messages: &[String]) -> String {
95	    let mut out = String::with_capacity(INVALID_ARGS_PRE.len() + INVALID_ARGS_POST.len() + 64);
96	    out.push_str(INVALID_ARGS_PRE);
97	    out.push_str("<ul>");
98	    for m in messages {
99	        out.push_str("<li>");
100	        out.push_str(&escape_text(m));
101	        out.push_str("</li>\n");
102	    }
103	    out.push_str("</ul>\n");
104	    out.push_str(INVALID_ARGS_POST);
105	    out
106	}
