7	//! Parse the wildcard path segment after `/thy/trace/<idx>/<section>/`
8	//! into a [`TheoryPath`], mirroring Haskell's `parseTheoryPath` in
9	//! `src/Web/Types.hs`.
10	//!
11	//! The frontend URL-encodes spaces and special characters, so we
12	//! percent-decode each segment first.
13	
14	use percent_encoding::percent_decode_str;
15	
16	/// A theory-internal path, mirroring Haskell `TheoryPath`.
17	#[derive(Debug, Clone, PartialEq, Eq)]
18	pub enum TheoryPath {
19	    Help,
20	    Rules,
21	    Message,
22	    Tactic,
23	    Lemma(String),
24	    Source { kind: SourceKind, src_idx: usize, case_idx: usize },
25	    Proof { lemma: String, sub: Vec<String> },
26	    Method { lemma: String, idx: usize, sub: Vec<String> },
27	    Edit(String),
28	    Add(String),
29	    Delete(String),
30	}
31	
32	#[derive(Debug, Clone, PartialEq, Eq)]
33	pub enum SourceKind { Refined, Raw }
34	
35	impl TheoryPath {
36	    /// Render to the same shape Haskell does (for emitting URLs back
37	    /// to the frontend).  See `renderTheoryPath` / the
38	    /// `prefixWithUnderscore` quirk in Haskell.
39	    pub fn render(&self) -> Vec<String> {
40	        let segs: Vec<String> = match self {
41	            TheoryPath::Help => vec!["help".into()],
42	            TheoryPath::Rules => vec!["rules".into()],
43	            TheoryPath::Message => vec!["message".into()],
44	            TheoryPath::Tactic => vec!["tactic".into()],
45	            TheoryPath::Lemma(n) => vec!["lemma".into(), n.clone()],
46	            TheoryPath::Source { kind, src_idx, case_idx } => {
47	                let k = match kind { SourceKind::Refined => "refined", SourceKind::Raw => "raw" };
48	                vec!["cases".into(), k.into(), src_idx.to_string(), case_idx.to_string()]
49	            }
50	            TheoryPath::Proof { lemma, sub } => {
51	                let mut v = vec!["proof".into(), lemma.clone()];
52	                v.extend(sub.iter().cloned());
53	                v
54	            }
55	            TheoryPath::Method { lemma, idx, sub } => {
56	                let mut v = vec!["method".into(), lemma.clone(), idx.to_string()];
57	                v.extend(sub.iter().cloned());
58	                v
59	            }
60	            TheoryPath::Edit(n) => vec!["edit".into(), n.clone()],
61	            TheoryPath::Add(n) => vec!["add".into(), n.clone()],
62	            TheoryPath::Delete(n) => vec!["delete".into(), n.clone()],
63	        };
64	        segs.iter().map(|s| prefix_with_underscore(s)).collect()
65	    }
66	}
67	
68	/// Canonical URL path-segment escaping shared by the theory/graph/proof
69	/// handlers: keep `[A-Za-z0-9_.-]`, percent-encode everything else.
70	pub fn url_path_escape(s: &str) -> String {
71	    s.chars().map(|c| match c {
72	        c if c.is_ascii_alphanumeric() || c == '_' || c == '-' || c == '.' => c.to_string(),
73	        c => format!("%{:02X}", c as u32),
74	    }).collect()
75	}
76	
77	/// Match Haskell's `prefixWithUnderscore`.  Empty + `_*` strings get
78	/// an extra leading `_` to avoid the empty-segment trap in Yesod.
79	pub fn prefix_with_underscore(s: &str) -> String {
80	    if s.is_empty() { "_".into() }
81	    else if s.starts_with('_') { format!("_{}", s) }
82	    else { s.to_string() }
83	}
84	
85	/// Encode a proof/method sub-path as leading-slash-joined URL segments,
86	/// applying [`prefix_with_underscore`] then [`url_path_escape`] to each
87	/// (mirrors Yesod `getUrlRender`'s per-segment encoding).  Empty input
88	/// yields the empty string, so callers can append the result directly
89	/// after `.../proof/<lemma>` or `.../method/<lemma>/<idx>`.
90	pub fn encode_sub_path(sub: &[String]) -> String {
91	    let mut s = String::new();
92	    for seg in sub {
93	        s.push('/');
94	        s.push_str(&url_path_escape(&prefix_with_underscore(seg)));
95	    }
96	    s
97	}
98	
99	/// Inverse of [`prefix_with_underscore`].
100	pub fn unprefix_underscore(s: &str) -> String {
101	    if s == "_" { String::new() }
102	    else if s.starts_with("__") { s[1..].to_string() }
103	    else { s.to_string() }
104	}
105	
106	/// Decode a wildcard-captured URL path into its logical segments: strip
107	/// leading slashes, split on `/`, drop empty segments, percent-decode,
108	/// then reverse [`prefix_with_underscore`] per segment.
109	///
110	/// Mirrors Haskell's `prefixWithUnderscore` invariant: empty case names
111	/// are encoded as `_` on the URL so adjacent slashes don't collapse, and
112	/// segments starting with `_` get a leading extra `_`;
113	/// [`unprefix_underscore`] reverses that here.  Trailing empty segments
114	/// are dropped by the empty-segment filter, so a leading-only vs both-end
115	/// trim of `/` is immaterial.
116	pub fn decode_segments(raw: &str) -> Vec<String> {
117	    raw
118	        .trim_start_matches('/')
119	        .split('/')
120	        .filter(|s| !s.is_empty())
121	        .map(|s| percent_decode_str(s).decode_utf8_lossy().to_string())
122	        .map(|s| unprefix_underscore(&s))
