126	/// Parse a wildcard-captured path (e.g. `proof/Alice/case_1/0`) into a
127	/// `TheoryPath`.  Returns `None` on malformed input.
128	pub fn parse(raw: &str) -> Option<TheoryPath> {
129	    parse_segs(&decode_segments(raw))
130	}
131	
132	fn parse_segs(segs: &[String]) -> Option<TheoryPath> {
133	    let (head, rest) = segs.split_first()?;
134	    match head.as_str() {
135	        "help" => Some(TheoryPath::Help),
136	        "rules" => Some(TheoryPath::Rules),
137	        "message" => Some(TheoryPath::Message),
138	        "tactic" => Some(TheoryPath::Tactic),
139	        "lemma" => rest.first().map(|n| TheoryPath::Lemma(n.clone())),
140	        "edit" => rest.first().map(|n| TheoryPath::Edit(n.clone())),
141	        "add" => rest.first().map(|n| TheoryPath::Add(n.clone())),
142	        "delete" => rest.first().map(|n| TheoryPath::Delete(n.clone())),
143	        "proof" => {
144	            // Mirror Haskell `parseProof` (`src/Web/Types.hs:417-456, see line 443`):
145	            //   parseProof (y:ys) = Just (TheoryProof y ys)
146	            // i.e. the sub-path is taken AS-IS (after `unprefixUnderscore`
147	            // each segment).  We do NOT pop trailing empty segments:
148	            // `proof/<lemma>` is the lemma root (sub = []), while
149	            // `proof/<lemma>/_` is the sub-path with a single empty
150	            // case name (sub = [""]) — these are distinct paths in
151	            // the proof tree (Simplify produces a child with case
152	            // name "" so this distinction matters at every step).
153	            let lemma = rest.first()?.clone();
154	            let sub: Vec<String> = rest.get(1..).unwrap_or(&[]).to_vec();
155	            Some(TheoryPath::Proof { lemma, sub })
156	        }
157	        "method" => {
158	            // Mirror Haskell `parseMethod` (`src/Web/Types.hs:417-456, see line 446`):
159	            //   parseMethod (y:z:zs) = safeRead z >>= Just . TheoryMethod y zs
160	            // i.e. the sub-path is taken AS-IS (after `unprefixUnderscore`
161	            // each segment) — including a single empty trailing
162	            // segment, which encodes the inner proof case named "".
163	            //
164	            // We intentionally do NOT pop trailing empty segments here
165	            // (same as the `proof` branch above): the method URL is constructed
166	            // from the proof-tree path, and each `/_` denotes a real
167	            // path segment.  Popping would conflate the lemma-root
168	            // application with applying-at-inner-empty-case (which
169	            // simplify produces a lot of), routing the click to the
170	            // wrong node.
171	            let lemma = rest.first()?.clone();
172	            let idx_s = rest.get(1)?;
173	            let idx: usize = idx_s.parse().ok()?;
174	            let sub: Vec<String> = rest.get(2..).unwrap_or(&[]).to_vec();
175	            Some(TheoryPath::Method { lemma, idx, sub })
176	        }
177	        "cases" => {
178	            let kind = match rest.first()?.as_str() {
179	                "refined" => SourceKind::Refined,
180	                "raw" => SourceKind::Raw,
181	                _ => return None,
182	            };
183	            let src_idx: usize = rest.get(1)?.parse().ok()?;
184	            let case_idx: usize = rest.get(2)?.parse().ok()?;
185	            Some(TheoryPath::Source { kind, src_idx, case_idx })
186	        }
187	        _ => None,
188	    }
189	}
