221	        let root = parse("proof/Alice").unwrap();
222	        assert!(matches!(&root, TheoryPath::Proof { lemma, sub } if lemma == "Alice" && sub.is_empty()),
223	            "got {:?}", root);
224	        let inner = parse("proof/Alice/_").unwrap();
225	        assert!(matches!(&inner, TheoryPath::Proof { lemma, sub } if lemma == "Alice" && sub == &[""]),
226	            "got {:?}", inner);
227	    }
