236	            if lemma == "Alice" && *idx == 1 && sub.is_empty()), "got {:?}", root);
237	        let inner = parse("method/Alice/1/_").unwrap();
238	        assert!(matches!(&inner, TheoryPath::Method { lemma, idx, sub }
239	            if lemma == "Alice" && *idx == 1 && sub == &[""]), "got {:?}", inner);
