29	/// `POST /` — File upload (multipart `uploadedTheory`).
30	pub async fn post(
31	    State(state): State<Arc<AppState>>,
32	    mut mp: Multipart,
33	) -> Response {
34	    // Mirror Haskell `postRootR` (src/Web/Handler.hs:785-812): a missing
35	    // `uploadedTheory` field → "Post request failed."; an empty file →
36	    // "No theory file given."; a load error → "Theory loading failed:…";
37	    // success → "Loaded new theory!".
38	    let mut alert_msg: Option<String> = None;
39	    let mut found_field = false;
40	    while let Some(field) = mp.next_field().await.unwrap_or(None) {
41	        if field.name() != Some("uploadedTheory") { continue; }
42	        found_field = true;
43	        let filename = field.file_name().unwrap_or("uploaded.spthy").to_string();
44	        let bytes: Bytes = match field.bytes().await {
45	            Ok(b) => b,
46	            Err(e) => { alert_msg = Some(format!("upload failed: {}", e)); break; }
47	        };
48	        if bytes.is_empty() {
49	            alert_msg = Some("No theory file given.".into());
50	            break;
51	        }
52	        let src = match std::str::from_utf8(&bytes) {
53	            Ok(s) => s.to_string(),
54	            Err(_) => { alert_msg = Some("upload was not valid UTF-8".into()); break; }
55	        };
56	        match theory_io::load_from_source(
57	            &src, TheoryOrigin::Upload(filename.clone()), &state.cfg.maude_path,
58	            state.cfg.derivcheck_timeout) {
59	            Ok(entry) => {
60	                let idx = state.store.insert(entry);
61	                tracing::info!(idx, file = %filename, "uploaded theory");
62	                // Haskell appends a ` WARNING: ignoring the following
63	                // wellformedness errors: …` suffix to this alert when the
64	                // report is non-empty (Handler.hs:807-811).  The Rust port
65	                // emits the bare message; the same report is still surfaced on
66	                // the theory page (the `wf-warning` banner + the source/message
67	                // `/* WARNING */` block, both from `entry.wf_report`).
68	                alert_msg = Some("Loaded new theory!".into());
69	            }
70	            // HS `postRootR` (src/Web/Handler.hs:785-817, see line 803):
71	            //   `setMessage $ "Theory loading failed:\n" <> toHtml (show err)`
72	            // — a NEWLINE separates the prefix from the error, not a space.
73	            // The '\n' survives both HS Blaze escaping and our `html_escape`
74	            // (which leaves '\n' untouched).
75	            Err(e) => { alert_msg = Some(format!("Theory loading failed:\n{}", e)); }
76	        }
77	        break;
78	    }
79	    if !found_field && alert_msg.is_none() {
80	        alert_msg = Some("Post request failed.".into());
81	    }
82	    let mut html = render_index(&state);
83	    if let Some(msg) = alert_msg {
84	        // Render a banner above the index — match Haskell's
85	        // `setMessage` lift into the layout.
86	        html = html.replacen(
87	            "<body>",
88	            &format!("<body><p class=\"message\">{}</p>", html_escape(&msg)),
89	            1,
90	        );
91	    }
92	    html_response(html)
93	}
