108	/// `GET /kill?path=<key>` — frontend uses this to cancel a
109	/// long-running search.  Haskell binds the `path` query parameter and
110	/// `invalidArgs` (400) when it's missing; on success it returns
111	/// `Canceled request!` as `text/plain`.
112	///
113	/// See `getKillThreadR` in `src/Web/Handler.hs:1422-1440`.
114	///
115	/// We don't yet wire a `tokio_util::sync::CancellationToken` registry,
116	/// so the "cancel" is a soft ack — but the 400-on-missing-path
117	/// semantics match Haskell exactly so frontend dispatch works.
118	pub async fn kill_thread(
119	    axum::extract::Query(q): axum::extract::Query<KillQuery>,
120	) -> impl IntoResponse {
121	    match q.path {
122	        Some(_key) => (
123	            StatusCode::OK,
124	            [(header::CONTENT_TYPE, "text/plain; charset=utf-8")],
125	            "Canceled request!",
126	        )
127	            .into_response(),
128	        None => (
129	            StatusCode::BAD_REQUEST,
130	            [(header::CONTENT_TYPE, "text/html; charset=utf-8")],
131	            "<!DOCTYPE html><html><head><title>Invalid Arguments</title></head>\
132	             <body><h1>Invalid Arguments</h1><ul><li>No path to kill specified!</li></ul></body></html>",
133	        )
134	            .into_response(),
135	    }
136	}
