27	/// Full overview/framing page (the one served at `/thy/trace/<idx>/overview/...`).
28	pub fn overview_page(entry: &TheoryEntry, path: &TheoryPath) -> String {
29	    let proof_state = proof_state(entry);
30	    let main_view = path_html(entry, path);
31	    // Route the page shell through the clean web layer (`web_clean::page`) for
32	    // local-origin theories.  The west/center panes are opaque prover content
33	    // (proof-script state, main-view HTML) supplied to the clean shell — which
34	    // is byte-identical to the ported local-origin template.  The clean shell
35	    // bakes in the local-origin header (Reload file / Append modified lemmas
36	    // actions); a non-local origin gates those off, which the clean shell does
37	    // not model, so that case keeps the ported template below.
38	    if matches!(entry.origin, crate::state::TheoryOrigin::Local(_)) {
39	        let filename = html_escape(&format!("{}.spthy", entry.name));
40	        let params = crate::web_clean::page::PageParams {
41	            theory_name: &entry.name,
