531	fn render_attrs(attrs: &[LemmaAttr]) -> String {
532	    if attrs.is_empty() { return String::new(); }
533	    let parts: Vec<String> = attrs.iter().map(|a| match a {
534	        LemmaAttr::Sources => "sources".into(),
535	        LemmaAttr::Reuse => "reuse".into(),
536	        LemmaAttr::DiffReuse => "diff_reuse".into(),
537	        LemmaAttr::UseInduction => "use_induction".into(),
538	        LemmaAttr::HideLemma(s) => format!("hide_lemma={}", s),
539	        LemmaAttr::Heuristic(s) => format!("heuristic={}", s),
540	        LemmaAttr::Output(xs) => format!("output={}", xs.join(",")),
541	        LemmaAttr::Left => "left".into(),
542	        LemmaAttr::Right => "right".into(),
543	        LemmaAttr::Hint(s) => s.clone(),
544	    }).collect();
545	    format!(" [{}]", parts.join(", "))
546	}
