633	/// Render the proof tree pane for a lemma at a given sub-path.
634	/// If a live [`ProofState`] is already built, use the actual tree;
635	/// otherwise fall back to the lemma's static info plus a build hint.
636	pub fn proof_html(entry: &TheoryEntry, lemma: &str, sub: &[String]) -> String {
637	    // HS `htmlThyPath` for `TheoryProof l p` (Web/Theory.hs:1019-1023):
638	    //   pp $ fromMaybe (text "No such lemma or proof path.") $ do
639	    //     lemma <- lookupLemma l thy
640	    //     subProofSnippet ... l p (getProofContext lemma thy)
641	    //       <$> resolveProofPath thy l p
642	    // → renders ONLY the sub-proof snippet at the resolved path; a missing
643	    //   lemma or unresolvable proof path yields the single fallback string.
644	    //   No lemma header, no formula echo, no whole-tree dump.
645	    if entry.typed_theory.lookup_lemma(lemma).is_none() {
646	        return "No such lemma or proof path.".into();
647	    }
648	    if let Some(ps) = &entry.proof_state {
649	        if let Some(root) = ps.get_root(lemma) {
650	            if let Some(n) = crate::handlers::proof_tree::navigate_at(&root, sub) {
651	                // `write_applicable_methods` execs every candidate method —
652	                // solver code that resolves user fun symbols via
653	                // thread-locals; install them for this render (tokio
654	                // workers start empty — see `ProofState::user_funs`).
655	                let _user_funs_guard = ps.install_user_funs();
656	                // Install this lemma's per-lemma `use_induction`/`heuristic`
657	                // into the shared ctx before ranking (HS `getProofContext`);
658	                // otherwise the Applicable Proof Methods order + ranking name
659	                // default to `AvoidInduction`/`Smart` and diverge from HS.
660	                let mut ctx_guard = ps.ctx.lock();
661	                ps.install_lemma_settings(&mut ctx_guard, lemma);
662	                return crate::handlers::proof_tree::render_sub_proof_snippet(
663	                    entry.idx, lemma, sub, n, &ctx_guard);
664	            }
665	        }
666	    }
667	    "No such lemma or proof path.".into()
668	}
