698	/// HS `ppSection header s = withTag "h2" [] (text header) $$ withTag "p"
699	/// [("class","monospace rules")] body` (Web/Theory.hs:928-931), rendered
700	/// through the `HtmlDoc` transformer.  Returns the pane fragment BEFORE
701	/// `postprocessHtmlDoc` (the caller `vcat`-joins fragments with `\n` and
702	/// postprocesses once): `<h2>HEADER</h2>` on its own line (from `$$`), then the
703	/// zero-width `<p …>` open glued before `body`'s first line and `</p>` after
704	/// its last (`withTag`).  `body` is already escaped + span-marked (rendered
705	/// under [`HtmlDocGuard`]); `header` is `text header` so it is entity-escaped
706	/// too.
707	fn section_fragment(header: &str, class: &str, body: &str) -> String {
708	    format!(
709	        "<h2>{}</h2>\n<p class=\"{}\">{}</p>",
710	        tamarin_theory::pretty_hpj::escape_html_entities(header),
711	        class,
712	        body,
713	    )
714	}
