723	/// `vcat` the pane fragments (HS `messageSnippet`/`rulesSnippet` top-level
724	/// `vcat`) then `postprocessHtmlDoc` once (leading spaces → `&nbsp;`, `<br/>`
725	/// per line).  `None` fragments are HS `emptyDoc` and vanish (`emptyDoc $$ x =
726	/// x`); an empty `String` fragment is HS `text ""` (a real blank line, e.g. the
727	/// absent-macros slot).
728	fn assemble_pane(fragments: Vec<Option<String>>) -> String {
729	    let pieces: Vec<String> = fragments.into_iter().flatten().collect();
730	    tamarin_theory::pretty_hpj::postprocess_html(&pieces.join("\n"))
731	}
