733	/// HS `messageSnippet` (Web/Theory.hs:920-931): Signature +
734	/// Construction/Deconstruction rule sections.
735	fn message_html(entry: &TheoryEntry) -> String {
736	    // HS renders `messageSnippet` through the `HtmlDoc Doc` transformer (same
737	    // `pp = renderHtmlDoc` dispatch as `rulesSnippet`, Web/Theory.hs:1014-1015):
738	    // every `text`/`char` is entity-escaped + measured escaped, keywords/
739	    // operators become `hl_*` spans, and the whole doc is postprocessed
740	    // (`<br/>`/`&nbsp;`).  Enable HtmlDoc mode for the pane build.
741	    let _html = tamarin_theory::pretty_hpj::HtmlDocGuard::enable();
742	    // `prettySignatureWithMaude thy._thySignature` — the same signature block
743	    // the theory body prints.
744	    let sig_block = tamarin_theory::pretty_theory::web_signature_block(
745	        &entry.typed_theory.signature.maude_sig);
746	    // `getClassifiedRules thy`'s `_crConstruct` / `_crDestruct`.  RS stores
747	    // proto rules separately, so `ctx.intruder_rules` is exactly HS's
748	    // `intrRulesAC`; an order-preserving filter reproduces the classification.
749	    let mut construct: Vec<IntrRuleAC> = Vec::new();
750	    let mut destruct: Vec<IntrRuleAC> = Vec::new();
751	    if let Some(ps) = &entry.proof_state {
752	        let ctx = ps.ctx.lock();
753	        for ir in &ctx.intruder_rules {
754	            if is_constr_intr(&ir.info) { construct.push(ir.clone()); }
755	            else if is_destr_intr(&ir.info) { destruct.push(ir.clone()); }
756	        }
757	    }
758	    // `map prettyRuleAC` joined by one blank line == `pretty_intruder_variants`
759	    // (HS `vcat (intersperse (text "") s)`).
760	    let construct_block = tamarin_theory::pretty_formula::pretty_intruder_variants(&construct);
761	    let destruct_block = tamarin_theory::pretty_formula::pretty_intruder_variants(&destruct);
762	    // HS `messageSnippet = vcat [ppSection "Signature" …, ppSection
763	    // "Construction Rules" …, ppSection "Deconstruction Rules" …]`.  `ppSection`
764	    // is ALWAYS emitted (even with an empty body), unlike `ppWithHeader`.
765	    assemble_pane(vec![
766	        Some(section_fragment("Signature", "monospace rules", &sig_block)),
767	        Some(section_fragment("Construction Rules", "monospace rules", &construct_block)),
768	        Some(section_fragment("Deconstruction Rules", "monospace rules", &destruct_block)),
769	    ])
770	}
