772	/// HS `showInjFact` (Web/Theory.hs:906-910): `showFactTag tag ++ "(" ++
773	/// intercalate "," ("id":positions) ++ ")"`.
774	fn show_inj_fact(
775	    tag: &tamarin_theory::fact::FactTag,
776	    behaviours: &[Vec<tamarin_theory::tools::injective_fact_instances::MonotonicBehaviour>],
777	) -> String {
778	    use tamarin_theory::fact::{FactTag, Multiplicity};
779	    let name = tamarin_theory::fact::fact_tag_name(tag);
780	    let head = match tag {
781	        FactTag::Proto(Multiplicity::Persistent, _, _) => format!("!{}", name),
782	        _ => name.to_string(),
783	    };
784	    let mut parts: Vec<String> = vec!["id".to_string()];
785	    for bb in behaviours {
786	        if bb.len() == 1 {
787	            parts.push(bb[0].to_string());
788	        } else {
789	            let inner: Vec<String> = bb.iter().map(|b| b.to_string()).collect();
790	            parts.push(format!("({})", inner.join(",")));
791	        }
792	    }
793	    format!("{}({})", head, parts.join(","))
794	}
