939	/// HS `casesInfo kind` (Web/Theory.hs:399-406): `(nCases, chainInfo)` where
940	/// `nCases = length (getSource kind thy)` and `nChains = sum $ map (sum .
941	/// unsolvedChainConstraints)`.  Rendered as `(N cases, deconstructions
942	/// complete)` or `(N cases, K partial deconstructions left)`.
943	fn source_case_counts(entry: &TheoryEntry, want_refined: bool) -> (usize, usize) {
944	    let source_lists = compute_source_lists(entry, want_refined);
945	    let n_cases = source_lists.len();
946	    let n_chains: usize = source_lists.iter()
947	        .flat_map(|(_, cases)| cases.iter())
948	        .map(|(_, sys)|
949	            tamarin_theory::constraint::solver::sources::unsolved_chain_constraints(sys))
950	        .sum();
951	    (n_cases, n_chains)
952	}
