//! Byte-parity guard for the R1 `main/help` routing (open-side test, headerless).
//!
//! `theory_path_main` now serves `main/help` through the clean
//! `producers::render_help_pane`. This asserts the clean producer emits the
//! byte-identical response the ported path did: the env line + shared static
//! help block, wrapped in the `{html,title}` JSON envelope, with the same
//! entity escaping (`tamarin_theory::pretty_hpj::escape_html_entities`, the
//! ported `help_html`'s escape) and the same serde envelope bytes
//! (`json_resp::html`). The static help block was separately verified
//! byte-identical to the ported `HELP_STATIC` constant.

use tamarin_server::producers;

fn ported_escape(s: &str) -> String {
    tamarin_theory::pretty_hpj::escape_html_entities(s)
}

/// Reproduce the exact bytes the ported dispatch produced for `main/help`:
/// `json_resp::html(title_for(Help), help_html(entry))`.
fn ported_help_response(name: &str, time: &str, origin: &str, banner: &str) -> String {
    let inner = format!(
        "<p>Theory: {} (Loaded at {} from {}) {}</p>{}",
        ported_escape(name),
        ported_escape(time),
        ported_escape(origin),
        banner,
        producers::section::HELP_STATIC_HTML, // byte-identical to ported HELP_STATIC
    );
    let title = format!("Theory: {}", name);
    // json_resp::html builds `json!({ "title": .., "html": .. })`; serde_json's
    // default map is sorted, so the serialized order is html-first, matching
    // the clean `html_envelope`.
    serde_json::to_string(&serde_json::json!({ "title": title, "html": inner })).unwrap()
}

fn routed_help_response(name: &str, time: &str, origin: &str, banner: &str) -> String {
    let pane = producers::HelpPane {
        theory_name: name.to_string(),
        load_time: time.to_string(),
        origin: origin.to_string(),
        wf_banner_html: banner.to_string(),
    };
    producers::render_help_pane(&pane)
}

#[test]
fn help_routing_is_byte_identical_local_origin() {
    let name = "issue193";
    let time = "12:34:56";
    let origin = "Local \"/tmp/issue193.spthy\"";
    let banner = "";
    assert_eq!(
        routed_help_response(name, time, origin, banner),
        ported_help_response(name, time, origin, banner),
    );
}

#[test]
